// Function to save data in localStorage
function saveToLocalStorage(key, data) {
    localStorage.setItem(key, JSON.stringify(data));
}

// Function to get data from localStorage
function getFromLocalStorage(key) {
    return JSON.parse(localStorage.getItem(key));
}

// Example usage: Save some data when the page is loaded
document.addEventListener('DOMContentLoaded', function() {
    let userData = { name: "John Doe", role: "Tukang" };
    saveToLocalStorage('userData', userData);

    // Retrieve data and display
    let storedData = getFromLocalStorage('userData');
    console.log(storedData.name); // Outputs: John Doe
});

